import axios from 'axios';
import { v4 as uuidv4 } from 'uuid';

const API_KEY = process.env.PAYROC_API_KEY!;
const TERMINAL_ID = process.env.PAYROC_TERMINAL_ID!;

async function getToken(): Promise<string> {
  const resp = await axios.post('https://identity.payroc.com/authorize', null, {
    headers: { 'x-api-key': API_KEY }
  });
  return resp.data.access_token;
}

async function createLink(orderId: string, amountMinor: number): Promise<string> {
  const token = await getToken();
  const resp = await axios.post(
    `https://api.uat.payroc.com/v1/processing-terminals/${TERMINAL_ID}/payment-links`,
    {
      type: 'single-use',
      authType: 'pre-auth',
      paymentMethods: ['bank_transfer'],
      order: {
        orderId,
        charge: { preset: { amount: amountMinor, currency: 'GBP' } }
      },
      expiresOn: '2026-12-31'
    },
    {
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
        'Idempotency-Key': uuidv4()
      }
    }
  );
  return resp.data.paymentUrl;
}
